patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 59002cd934ab..2b9ca70cbed8 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -2936,11 +2936,45 @@ static Value *simplifyICmpWithZero(CmpPredicate Pred, Value *LHS, Value *RHS,
   case ICmpInst::ICMP_ULE:
     if (isKnownNonZero(LHS, Q))
       return getFalse(ITy);
+    // (X | Y) != 0 if X != Y.
+    {
+      Value *A, *B;
+      if (match(LHS, m_Or(m_Value(A), m_Value(B)))) {
+        if (isKnownNonEqual(A, B, Q))
+          return getFalse(ITy);
+        if (std::optional<bool> Imp = isImpliedByDomCondition(
+                ICmpInst::ICMP_NE, A, B, Q.CxtI, Q.DL))
+          if (*Imp)
+            return getFalse(ITy);
+        // Also check if equality is known false.
+        if (std::optional<bool> Imp = isImpliedByDomCondition(
+                ICmpInst::ICMP_EQ, A, B, Q.CxtI, Q.DL))
+          if (!*Imp)
+            return getFalse(ITy);
+      }
+    }
     break;
   case ICmpInst::ICMP_NE:
   case ICmpInst::ICMP_UGT:
     if (isKnownNonZero(LHS, Q))
       return getTrue(ITy);
+    // (X | Y) != 0 if X != Y.
+    {
+      Value *A, *B;
+      if (match(LHS, m_Or(m_Value(A), m_Value(B)))) {
+        if (isKnownNonEqual(A, B, Q))
+          return getTrue(ITy);
+        if (std::optional<bool> Imp = isImpliedByDomCondition(
+                ICmpInst::ICMP_NE, A, B, Q.CxtI, Q.DL))
+          if (*Imp)
+            return getTrue(ITy);
+        // Also check if equality is known false.
+        if (std::optional<bool> Imp = isImpliedByDomCondition(
+                ICmpInst::ICMP_EQ, A, B, Q.CxtI, Q.DL))
+          if (!*Imp)
+            return getTrue(ITy);
+      }
+    }
     break;
   case ICmpInst::ICMP_SLT: {
     KnownBits LHSKnown = computeKnownBits(LHS, /* Depth */ 0, Q);

