   194 | static Value *expandBinOp(Instruction::BinaryOps Opcode, Value *V,
   195 |                           Value *OtherOp, Instruction::BinaryOps OpcodeToExpand,
   196 |                           const SimplifyQuery &Q, unsigned MaxRecurse) {
