   626 |   // Therefore, the xor must be clearing the already set sign bit of Y.
   627 |   if ((IsNSW || IsNUW) && match(Op1, m_SignMask()) &&
   628 |       match(Op0, m_Xor(m_Value(Y), m_SignMask())))
