  4067 | Value *llvm::simplifyICmpInst(CmpPredicate Predicate, Value *LHS, Value *RHS,
  4068 |                               const SimplifyQuery &Q) {
  4069 |   return ::simplifyICmpInst(Predicate, LHS, RHS, Q, RecursionLimit);
