  4072 | /// Given operands for an FCmpInst, see if we can fold the result.
  4073 | /// If not, this returns null.
  4074 | static Value *simplifyFCmpInst(CmpPredicate Pred, Value *LHS, Value *RHS,
  4075 |                                FastMathFlags FMF, const SimplifyQuery &Q,
  4076 |                                unsigned MaxRecurse) {
  4077 |   assert(CmpInst::isFPPredicate(Pred) && "Not an FP compare!");
  4078 | 
  4079 |   if (Constant *CLHS = dyn_cast<Constant>(LHS)) {
  4080 |     if (Constant *CRHS = dyn_cast<Constant>(RHS))
  4081 |       return ConstantFoldCompareInstOperands(Pred, CLHS, CRHS, Q.DL, Q.TLI,
  4082 |                                              Q.CxtI);
  4083 | 
  4084 |     // If we have a constant, make sure it is on the RHS.
  4085 |     std::swap(LHS, RHS);
  4086 |     Pred = CmpInst::getSwappedPredicate(Pred);
  4087 |   }
  4088 | 
  4089 |   // Fold trivial predicates.
  4090 |   Type *RetTy = getCompareTy(LHS);
  4091 |   if (Pred == FCmpInst::FCMP_FALSE)
  4092 |     return getFalse(RetTy);
  4093 |   if (Pred == FCmpInst::FCMP_TRUE)
  4094 |     return getTrue(RetTy);
  4095 | 
  4096 |   // fcmp pred x, poison and  fcmp pred poison, x
  4097 |   // fold to poison
  4098 |   if (isa<PoisonValue>(LHS) || isa<PoisonValue>(RHS))
  4099 |     return PoisonValue::get(RetTy);
  4100 | 
  4101 |   // fcmp pred x, undef  and  fcmp pred undef, x
  4102 |   // fold to true if unordered, false if ordered
  4103 |   if (Q.isUndefValue(LHS) || Q.isUndefValue(RHS)) {
  4104 |     // Choosing NaN for the undef will always make unordered comparison succeed
  4105 |     // and ordered comparison fail.
  4106 |     return ConstantInt::get(RetTy, CmpInst::isUnordered(Pred));
  4107 |   }
  4108 | 
  4109 |   // fcmp x,x -> true/false.  Not all compares are foldable.
  4110 |   if (LHS == RHS) {
  4111 |     if (CmpInst::isTrueWhenEqual(Pred))
  4112 |       return getTrue(RetTy);
  4113 |     if (CmpInst::isFalseWhenEqual(Pred))
  4114 |       return getFalse(RetTy);
  4115 |   }
  4116 | 
  4117 |   // Fold (un)ordered comparison if we can determine there are no NaNs.
  4118 |   //
  4119 |   // This catches the 2 variable input case, constants are handled below as a
  4120 |   // class-like compare.
  4121 |   if (Pred == FCmpInst::FCMP_ORD || Pred == FCmpInst::FCMP_UNO) {
  4122 |     KnownFPClass RHSClass =
  4123 |         computeKnownFPClass(RHS, fcAllFlags, /*Depth=*/0, Q);
  4124 |     KnownFPClass LHSClass =
  4125 |         computeKnownFPClass(LHS, fcAllFlags, /*Depth=*/0, Q);
  4126 | 
  4127 |     if (FMF.noNaNs() ||
  4128 |         (RHSClass.isKnownNeverNaN() && LHSClass.isKnownNeverNaN()))
  4129 |       return ConstantInt::get(RetTy, Pred == FCmpInst::FCMP_ORD);
  4130 | 
  4131 |     if (RHSClass.isKnownAlwaysNaN() || LHSClass.isKnownAlwaysNaN())
  4132 |       return ConstantInt::get(RetTy, Pred == CmpInst::FCMP_UNO);
  4133 |   }
  4134 | 
  4135 |   const APFloat *C = nullptr;
  4136 |   match(RHS, m_APFloatAllowPoison(C));
  4137 |   std::optional<KnownFPClass> FullKnownClassLHS;
  4138 | 
  4139 |   // Lazily compute the possible classes for LHS. Avoid computing it twice if
  4140 |   // RHS is a 0.
  4141 |   auto computeLHSClass = [=, &FullKnownClassLHS](FPClassTest InterestedFlags =
  4142 |                                                      fcAllFlags) {
  4143 |     if (FullKnownClassLHS)
  4144 |       return *FullKnownClassLHS;
  4145 |     return computeKnownFPClass(LHS, FMF, InterestedFlags, 0, Q);
  4146 |   };
  4147 | 
  4148 |   if (C && Q.CxtI) {
  4149 |     // Fold out compares that express a class test.
  4150 |     //
  4151 |     // FIXME: Should be able to perform folds without context
  4152 |     // instruction. Always pass in the context function?
  4153 | 
  4154 |     const Function *ParentF = Q.CxtI->getFunction();
  4155 |     auto [ClassVal, ClassTest] = fcmpToClassTest(Pred, *ParentF, LHS, C);
  4156 |     if (ClassVal) {
  4157 |       FullKnownClassLHS = computeLHSClass();
  4158 |       if ((FullKnownClassLHS->KnownFPClasses & ClassTest) == fcNone)
  4159 |         return getFalse(RetTy);
  4160 |       if ((FullKnownClassLHS->KnownFPClasses & ~ClassTest) == fcNone)
  4161 |         return getTrue(RetTy);
  4162 |     }
  4163 |   }
  4164 | 
  4165 |   // Handle fcmp with constant RHS.
  4166 |   if (C) {
  4167 |     // TODO: If we always required a context function, we wouldn't need to
  4168 |     // special case nans.
  4169 |     if (C->isNaN())
  4170 |       return ConstantInt::get(RetTy, CmpInst::isUnordered(Pred));
  4171 | 
  4172 |     // TODO: Need version fcmpToClassTest which returns implied class when the
  4173 |     // compare isn't a complete class test. e.g. > 1.0 implies fcPositive, but
  4174 |     // isn't implementable as a class call.
  4175 |     if (C->isNegative() && !C->isNegZero()) {
  4176 |       FPClassTest Interested = KnownFPClass::OrderedLessThanZeroMask;
  4177 | 
  4178 |       // TODO: We can catch more cases by using a range check rather than
  4179 |       //       relying on CannotBeOrderedLessThanZero.
  4180 |       switch (Pred) {
  4181 |       case FCmpInst::FCMP_UGE:
  4182 |       case FCmpInst::FCMP_UGT:
  4183 |       case FCmpInst::FCMP_UNE: {
  4184 |         KnownFPClass KnownClass = computeLHSClass(Interested);
  4185 | 
  4186 |         // (X >= 0) implies (X > C) when (C < 0)
  4187 |         if (KnownClass.cannotBeOrderedLessThanZero())
  4188 |           return getTrue(RetTy);
  4189 |         break;
  4190 |       }
  4191 |       case FCmpInst::FCMP_OEQ:
  4192 |       case FCmpInst::FCMP_OLE:
  4193 |       case FCmpInst::FCMP_OLT: {
  4194 |         KnownFPClass KnownClass = computeLHSClass(Interested);
  4195 | 
  4196 |         // (X >= 0) implies !(X < C) when (C < 0)
  4197 |         if (KnownClass.cannotBeOrderedLessThanZero())
  4198 |           return getFalse(RetTy);
  4199 |         break;
  4200 |       }
  4201 |       default:
  4202 |         break;
  4203 |       }
  4204 |     }
  4205 |     // Check comparison of [minnum/maxnum with constant] with other constant.
  4206 |     const APFloat *C2;
  4207 |     if ((match(LHS, m_Intrinsic<Intrinsic::minnum>(m_Value(), m_APFloat(C2))) &&
  4208 |          *C2 < *C) ||
  4209 |         (match(LHS, m_Intrinsic<Intrinsic::maxnum>(m_Value(), m_APFloat(C2))) &&
  4210 |          *C2 > *C)) {
  4211 |       bool IsMaxNum =
  4212 |           cast<IntrinsicInst>(LHS)->getIntrinsicID() == Intrinsic::maxnum;
  4213 |       // The ordered relationship and minnum/maxnum guarantee that we do not
  4214 |       // have NaN constants, so ordered/unordered preds are handled the same.
  4215 |       switch (Pred) {
  4216 |       case FCmpInst::FCMP_OEQ:
  4217 |       case FCmpInst::FCMP_UEQ:
  4218 |         // minnum(X, LesserC)  == C --> false
  4219 |         // maxnum(X, GreaterC) == C --> false
  4220 |         return getFalse(RetTy);
  4221 |       case FCmpInst::FCMP_ONE:
  4222 |       case FCmpInst::FCMP_UNE:
  4223 |         // minnum(X, LesserC)  != C --> true
  4224 |         // maxnum(X, GreaterC) != C --> true
  4225 |         return getTrue(RetTy);
  4226 |       case FCmpInst::FCMP_OGE:
  4227 |       case FCmpInst::FCMP_UGE:
  4228 |       case FCmpInst::FCMP_OGT:
  4229 |       case FCmpInst::FCMP_UGT:
  4230 |         // minnum(X, LesserC)  >= C --> false
  4231 |         // minnum(X, LesserC)  >  C --> false
  4232 |         // maxnum(X, GreaterC) >= C --> true
  4233 |         // maxnum(X, GreaterC) >  C --> true
  4234 |         return ConstantInt::get(RetTy, IsMaxNum);
  4235 |       case FCmpInst::FCMP_OLE:
  4236 |       case FCmpInst::FCMP_ULE:
  4237 |       case FCmpInst::FCMP_OLT:
  4238 |       case FCmpInst::FCMP_ULT:
  4239 |         // minnum(X, LesserC)  <= C --> true
  4240 |         // minnum(X, LesserC)  <  C --> true
  4241 |         // maxnum(X, GreaterC) <= C --> false
  4242 |         // maxnum(X, GreaterC) <  C --> false
  4243 |         return ConstantInt::get(RetTy, !IsMaxNum);
  4244 |       default:
  4245 |         // TRUE/FALSE/ORD/UNO should be handled before this.
  4246 |         llvm_unreachable("Unexpected fcmp predicate");
  4247 |       }
  4248 |     }
  4249 |   }
  4250 | 
  4251 |   // TODO: Could fold this with above if there were a matcher which returned all
  4252 |   // classes in a non-splat vector.
  4253 |   if (match(RHS, m_AnyZeroFP())) {
  4254 |     switch (Pred) {
  4255 |     case FCmpInst::FCMP_OGE:
  4256 |     case FCmpInst::FCMP_ULT: {
  4257 |       FPClassTest Interested = KnownFPClass::OrderedLessThanZeroMask;
  4258 |       if (!FMF.noNaNs())
  4259 |         Interested |= fcNan;
  4260 | 
  4261 |       KnownFPClass Known = computeLHSClass(Interested);
  4262 | 
  4263 |       // Positive or zero X >= 0.0 --> true
  4264 |       // Positive or zero X <  0.0 --> false
  4265 |       if ((FMF.noNaNs() || Known.isKnownNeverNaN()) &&
  4266 |           Known.cannotBeOrderedLessThanZero())
  4267 |         return Pred == FCmpInst::FCMP_OGE ? getTrue(RetTy) : getFalse(RetTy);
  4268 |       break;
  4269 |     }
  4270 |     case FCmpInst::FCMP_UGE:
  4271 |     case FCmpInst::FCMP_OLT: {
  4272 |       FPClassTest Interested = KnownFPClass::OrderedLessThanZeroMask;
  4273 |       KnownFPClass Known = computeLHSClass(Interested);
  4274 | 
  4275 |       // Positive or zero or nan X >= 0.0 --> true
  4276 |       // Positive or zero or nan X <  0.0 --> false
  4277 |       if (Known.cannotBeOrderedLessThanZero())
  4278 |         return Pred == FCmpInst::FCMP_UGE ? getTrue(RetTy) : getFalse(RetTy);
  4279 |       break;
  4280 |     }
  4281 |     default:
  4282 |       break;
  4283 |     }
  4284 |   }
  4285 | 
  4286 |   // If the comparison is with the result of a select instruction, check whether
  4287 |   // comparing with either branch of the select always yields the same value.
  4288 |   if (isa<SelectInst>(LHS) || isa<SelectInst>(RHS))
  4289 |     if (Value *V = threadCmpOverSelect(Pred, LHS, RHS, Q, MaxRecurse))
  4290 |       return V;
  4291 | 
  4292 |   // If the comparison is with the result of a phi instruction, check whether
  4293 |   // doing the compare with each incoming phi value yields a common result.
  4294 |   if (isa<PHINode>(LHS) || isa<PHINode>(RHS))
  4295 |     if (Value *V = threadCmpOverPHI(Pred, LHS, RHS, Q, MaxRecurse))
  4296 |       return V;
  4297 | 
  4298 |   return nullptr;
  4299 | }
