  4301 | Value *llvm::simplifyFCmpInst(CmpPredicate Predicate, Value *LHS, Value *RHS,
  4302 |                               FastMathFlags FMF, const SimplifyQuery &Q) {
  4303 |   return ::simplifyFCmpInst(Predicate, LHS, RHS, FMF, Q, RecursionLimit);
