  4305 | 
  4306 | static Value *simplifyWithOpsReplaced(Value *V,
  4307 |                                       ArrayRef<std::pair<Value *, Value *>> Ops,
  4308 |                                       const SimplifyQuery &Q,
  4309 |                                       bool AllowRefinement,
  4310 |                                       SmallVectorImpl<Instruction *> *DropFlags,
  4311 |                                       unsigned MaxRecurse) {
  4312 |   assert((AllowRefinement || !Q.CanUseUndef) &&
  4313 |          "If AllowRefinement=false then CanUseUndef=false");
  4314 |   for (const auto &OpAndRepOp : Ops) {
  4315 |     // We cannot replace a constant, and shouldn't even try.
  4316 |     if (isa<Constant>(OpAndRepOp.first))
  4317 |       return nullptr;
  4318 | 
  4319 |     // Trivial replacement.
  4320 |     if (V == OpAndRepOp.first)
  4321 |       return OpAndRepOp.second;
  4322 |   }
  4323 | 
  4324 |   if (!MaxRecurse--)
  4325 |     return nullptr;
  4326 | 
  4327 |   auto *I = dyn_cast<Instruction>(V);
  4328 |   if (!I)
  4329 |     return nullptr;
  4330 | 
  4331 |   // The arguments of a phi node might refer to a value from a previous
  4332 |   // cycle iteration.
  4333 |   if (isa<PHINode>(I))
  4334 |     return nullptr;
  4335 | 
  4336 |   // Don't fold away llvm.is.constant checks based on assumptions.
  4337 |   if (match(I, m_Intrinsic<Intrinsic::is_constant>()))
  4338 |     return nullptr;
  4339 | 
  4340 |   // Don't simplify freeze.
  4341 |   if (isa<FreezeInst>(I))
  4342 |     return nullptr;
  4343 | 
  4344 |   for (const auto &OpAndRepOp : Ops) {
  4345 |     // For vector types, the simplification must hold per-lane, so forbid
  4346 |     // potentially cross-lane operations like shufflevector.
  4347 |     if (OpAndRepOp.first->getType()->isVectorTy() &&
  4348 |         !isNotCrossLaneOperation(I))
  4349 |       return nullptr;
  4350 |   }
  4351 | 
  4352 |   // Replace Op with RepOp in instruction operands.
  4353 |   SmallVector<Value *, 8> NewOps;
  4354 |   bool AnyReplaced = false;
  4355 |   for (Value *InstOp : I->operands()) {
  4356 |     if (Value *NewInstOp = simplifyWithOpsReplaced(
  4357 |             InstOp, Ops, Q, AllowRefinement, DropFlags, MaxRecurse)) {
  4358 |       NewOps.push_back(NewInstOp);
  4359 |       AnyReplaced = InstOp != NewInstOp;
  4360 |     } else {
  4361 |       NewOps.push_back(InstOp);
  4362 |     }
  4363 | 
  4364 |     // Bail out if any operand is undef and SimplifyQuery disables undef
  4365 |     // simplification. Constant folding currently doesn't respect this option.
  4366 |     if (isa<UndefValue>(NewOps.back()) && !Q.CanUseUndef)
  4367 |       return nullptr;
  4368 |   }
  4369 | 
  4370 |   if (!AnyReplaced)
  4371 |     return nullptr;
  4372 | 
  4373 |   if (!AllowRefinement) {
  4374 |     // General InstSimplify functions may refine the result, e.g. by returning
  4375 |     // a constant for a potentially poison value. To avoid this, implement only
  4376 |     // a few non-refining but profitable transforms here.
  4377 | 
  4378 |     if (auto *BO = dyn_cast<BinaryOperator>(I)) {
  4379 |       unsigned Opcode = BO->getOpcode();
  4380 |       // id op x -> x, x op id -> x
  4381 |       // Exclude floats, because x op id may produce a different NaN value.
  4382 |       if (!BO->getType()->isFPOrFPVectorTy()) {
  4383 |         if (NewOps[0] == ConstantExpr::getBinOpIdentity(Opcode, I->getType()))
  4384 |           return NewOps[1];
  4385 |         if (NewOps[1] == ConstantExpr::getBinOpIdentity(Opcode, I->getType(),
  4386 |                                                         /* RHS */ true))
  4387 |           return NewOps[0];
  4388 |       }
  4389 | 
  4390 |       // x & x -> x, x | x -> x
  4391 |       if ((Opcode == Instruction::And || Opcode == Instruction::Or) &&
  4392 |           NewOps[0] == NewOps[1]) {
  4393 |         // or disjoint x, x results in poison.
  4394 |         if (auto *PDI = dyn_cast<PossiblyDisjointInst>(BO)) {
  4395 |           if (PDI->isDisjoint()) {
  4396 |             if (!DropFlags)
  4397 |               return nullptr;
  4398 |             DropFlags->push_back(BO);
  4399 |           }
  4400 |         }
  4401 |         return NewOps[0];
  4402 |       }
  4403 | 
  4404 |       // x - x -> 0, x ^ x -> 0. This is non-refining, because x is non-poison
  4405 |       // by assumption and this case never wraps, so nowrap flags can be
  4406 |       // ignored.
  4407 |       if ((Opcode == Instruction::Sub || Opcode == Instruction::Xor) &&
  4408 |           NewOps[0] == NewOps[1] &&
  4409 |           any_of(Ops, [=](const auto &Rep) { return NewOps[0] == Rep.second; }))
  4410 |         return Constant::getNullValue(I->getType());
  4411 | 
  4412 |       // If we are substituting an absorber constant into a binop and extra
  4413 |       // poison can't leak if we remove the select -- because both operands of
  4414 |       // the binop are based on the same value -- then it may be safe to replace
  4415 |       // the value with the absorber constant. Examples:
  4416 |       // (Op == 0) ? 0 : (Op & -Op)            --> Op & -Op
