  %cond = icmp ne i8 %x, %y
  br i1 %cond, label %if.then, label %if.else

if.then:
  %or = or i8 %x, %y
  %cmp = icmp eq i8 %or, 0
  ret i1 %cmp

if.else:
  ret i1 false
}

